package com.financesystem.util;

import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

import java.sql.Connection;
import java.sql.DriverManager;
import java.sql.SQLException;

public class DatabaseUtil {
    private static final Logger logger = LoggerFactory.getLogger(DatabaseUtil.class);

    // Database credentials from environment variables
    private static final String DB_URL = System.getenv("DB_URL");
    private static final String DB_USER = System.getenv("DB_USER");
    private static final String DB_PASSWORD = System.getenv("DB_PASSWORD");

    static {
        // Basic check for environment variables
        if (DB_URL == null || DB_USER == null || DB_PASSWORD == null) {
            logger.error("Database environment variables (DB_URL, DB_USER, DB_PASSWORD) are not set.");
            // In a real application, you might want to throw an exception or exit.
            // For this example, we'll just log and let connection attempts fail.
        }
    }

    /**
     * Establishes a connection to the database.
     *
     * @return A valid Connection object.
     * @throws SQLException If a database access error occurs.
     */
    public static Connection getConnection() throws SQLException {
        if (DB_URL == null || DB_USER == null || DB_PASSWORD == null) {
            throw new SQLException("Database credentials are not properly configured.");
        }
        try {
            // Register JDBC driver (optional for modern JDBC drivers, but good practice)
            // Class.forName("com.mysql.cj.jdbc.Driver"); // For MySQL 8+
            logger.debug("Attempting to connect to database...");
            return DriverManager.getConnection(DB_URL, DB_USER, DB_PASSWORD);
        } catch (SQLException e) {
            logger.error("Failed to connect to database: {}", e.getMessage());
            throw e;
        }
    }

    /**
     * Closes a database connection, statement, and result set.
     *
     * @param connection The Connection object to close.
     */
    public static void close(Connection connection) {
        try {
            if (connection != null && !connection.isClosed()) {
                connection.close();
                logger.debug("Database connection closed.");
            }
        } catch (SQLException e) {
            logger.error("Error closing database connection: {}", e.getMessage());
        }
    }

    // Overloaded close methods for Statement and ResultSet can be added if needed
    // For simplicity, this example focuses on Connection.
}

