package com.financesystem.service;

import com.financesystem.model.User;
import com.financesystem.util.DatabaseUtil;
import com.financesystem.util.PasswordUtil;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

import java.sql.Connection;
import java.sql.PreparedStatement;
import java.sql.ResultSet;
import java.sql.SQLException;
import java.sql.Statement;

public class AuthService {
    private static final Logger logger = LoggerFactory.getLogger(AuthService.class);

    /**
     * Registers a new user with a hashed password.
     *
     * @param username The desired username.
     * @param password The plain-text password.
     * @return The registered User object if successful, null otherwise.
     */
    public User registerUser(String username, String password) {
        if (username == null || username.trim().isEmpty() || password == null || password.isEmpty()) {
            logger.warn("Attempted to register user with invalid username or password.");
            return null;
        }

        String hashedPassword = PasswordUtil.hashPassword(password);
        String sql = "INSERT INTO users (username, password_hash) VALUES (?, ?)";
        Connection conn = null;
        PreparedStatement pstmt = null;
        ResultSet rs = null;
        User newUser = null;

        try {
            conn = DatabaseUtil.getConnection();
            pstmt = conn.prepareStatement(sql, Statement.RETURN_GENERATED_KEYS);
            pstmt.setString(1, username);
            pstmt.setString(2, hashedPassword);

            int affectedRows = pstmt.executeUpdate();
            if (affectedRows > 0) {
                rs = pstmt.getGeneratedKeys();
                if (rs.next()) {
                    int id = rs.getInt(1);
                    newUser = new User(id, username, hashedPassword);
                    logger.info("User registered successfully: {}", username);
                }
            } else {
                logger.warn("User registration failed for username: {}", username);
            }
        } catch (SQLException e) {
            if (e.getSQLState().equals("23000")) { // SQLState for duplicate entry (e.g., unique constraint violation)
                logger.warn("Registration failed: Username '{}' already exists.", username);
            } else {
                logger.error("Database error during user registration for {}: {}", username, e.getMessage());
            }
        } finally {
            try {
                if (rs != null) rs.close();
                if (pstmt != null) pstmt.close();
                if (conn != null) conn.close();
            } catch (SQLException e) {
                logger.error("Error closing resources after registration: {}", e.getMessage());
            }
        }
        return newUser;
    }

    /**
     * Authenticates a user.
     *
     * @param username The username.
     * @param password The plain-text password.
     * @return The authenticated User object if successful, null otherwise.
     */
    public User loginUser(String username, String password) {
        if (username == null || username.trim().isEmpty() || password == null || password.isEmpty()) {
            logger.warn("Attempted to login with invalid username or password.");
            return null;
        }

        String sql = "SELECT id, username, password_hash FROM users WHERE username = ?";
        Connection conn = null;
        PreparedStatement pstmt = null;
        ResultSet rs = null;
        User user = null;

        try {
            conn = DatabaseUtil.getConnection();
            pstmt = conn.prepareStatement(sql);
            pstmt.setString(1, username);

            rs = pstmt.executeQuery();
            if (rs.next()) {
                String storedHash = rs.getString("password_hash");
                if (PasswordUtil.checkPassword(password, storedHash)) {
                    user = new User(rs.getInt("id"), rs.getString("username"), storedHash);
                    logger.info("User logged in successfully: {}", username);
                } else {
                    logger.info("Login failed for user '{}': Incorrect password.", username);
                }
            } else {
                logger.info("Login failed: User '{}' not found.", username);
            }
        } catch (SQLException e) {
            logger.error("Database error during user login for {}: {}", username, e.getMessage());
        } finally {
            try {
                if (rs != null) rs.close();
                if (pstmt != null) pstmt.close();
                if (conn != null) conn.close();
            } catch (SQLException e) {
                logger.error("Error closing resources after login: {}", e.getMessage());
            }
        }
        return user;
    }

    /**
     * Finds a user by username.
     * @param username The username to search for.
     * @return The User object if found, null otherwise.
     */
    public User findUserByUsername(String username) {
        String sql = "SELECT id, username, password_hash FROM users WHERE username = ?";
        Connection conn = null;
        PreparedStatement pstmt = null;
        ResultSet rs = null;
        User user = null;

        try {
            conn = DatabaseUtil.getConnection();
            pstmt = conn.prepareStatement(sql);
            pstmt.setString(1, username);
            rs = pstmt.executeQuery();

            if (rs.next()) {
                user = new User(rs.getInt("id"), rs.getString("username"), rs.getString("password_hash"));
            }
        } catch (SQLException e) {
            logger.error("Database error finding user by username {}: {}", username, e.getMessage());
        } finally {
            try {
                if (rs != null) rs.close();
                if (pstmt != null) pstmt.close();
                if (conn != null) conn.close();
            } catch (SQLException e) {
                logger.error("Error closing resources after finding user: {}", e.getMessage());
            }
        }
        return user;
    }
}

