package com.financesystem.service;

import com.financesystem.model.Transaction;
import com.financesystem.util.DatabaseUtil;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

import java.math.BigDecimal;
import java.sql.Connection;
import java.sql.Date;
import java.sql.PreparedStatement;
import java.sql.ResultSet;
import java.sql.SQLException;
import java.sql.Statement;
import java.time.LocalDate;
import java.util.ArrayList;
import java.util.List;

public class TransactionService {
    private static final Logger logger = LoggerFactory.getLogger(TransactionService.class);

    /**
     * Adds a new transaction for a user.
     *
     * @param transaction The transaction object to add.
     * @return The added Transaction object with its generated ID, or null if failed.
     */
    public Transaction addTransaction(Transaction transaction) {
        if (transaction == null || transaction.getUserId() <= 0 || transaction.getAmount() == null ||
            transaction.getAmount().compareTo(BigDecimal.ZERO) <= 0 || transaction.getType() == null ||
            transaction.getTransactionDate() == null) {
            logger.warn("Attempted to add an invalid transaction.");
            return null;
        }

        String sql = "INSERT INTO transactions (user_id, type, amount, description, transaction_date) VALUES (?, ?, ?, ?, ?)";
        Connection conn = null;
        PreparedStatement pstmt = null;
        ResultSet rs = null;
        Transaction newTransaction = null;

        try {
            conn = DatabaseUtil.getConnection();
            pstmt = conn.prepareStatement(sql, Statement.RETURN_GENERATED_KEYS);
            pstmt.setInt(1, transaction.getUserId());
            pstmt.setString(2, transaction.getType().name());
            pstmt.setBigDecimal(3, transaction.getAmount());
            pstmt.setString(4, transaction.getDescription());
            pstmt.setDate(5, Date.valueOf(transaction.getTransactionDate()));

            int affectedRows = pstmt.executeUpdate();
            if (affectedRows > 0) {
                rs = pstmt.getGeneratedKeys();
                if (rs.next()) {
                    int id = rs.getInt(1);
                    newTransaction = new Transaction(id, transaction.getUserId(), transaction.getType(),
                                                     transaction.getAmount(), transaction.getDescription(),
                                                     transaction.getTransactionDate());
                    logger.info("Transaction added successfully for user {}: {}", transaction.getUserId(), transaction.getType());
                }
            } else {
                logger.warn("Failed to add transaction for user {}.", transaction.getUserId());
            }
        } catch (SQLException e) {
            logger.error("Database error adding transaction for user {}: {}", transaction.getUserId(), e.getMessage());
        } finally {
            try {
                if (rs != null) rs.close();
                if (pstmt != null) pstmt.close();
                if (conn != null) conn.close();
            } catch (SQLException e) {
                logger.error("Error closing resources after adding transaction: {}", e.getMessage());
            }
        }
        return newTransaction;
    }

    /**
     * Retrieves all transactions for a specific user.
     *
     * @param userId The ID of the user.
     * @return A list of transactions for the user.
     */
    public List<Transaction> getTransactionsByUserId(int userId) {
        List<Transaction> transactions = new ArrayList<>();
        String sql = "SELECT id, user_id, type, amount, description, transaction_date FROM transactions WHERE user_id = ? ORDER BY transaction_date DESC";
        Connection conn = null;
        PreparedStatement pstmt = null;
        ResultSet rs = null;

        try {
            conn = DatabaseUtil.getConnection();
            pstmt = conn.prepareStatement(sql);
            pstmt.setInt(1, userId);
            rs = pstmt.executeQuery();

            while (rs.next()) {
                Transaction transaction = new Transaction(
                    rs.getInt("id"),
                    rs.getInt("user_id"),
                    Transaction.Type.valueOf(rs.getString("type")),
                    rs.getBigDecimal("amount"),
                    rs.getString("description"),
                    rs.getDate("transaction_date").toLocalDate()
                );
                transactions.add(transaction);
            }
            logger.debug("Retrieved {} transactions for user {}.", transactions.size(), userId);
        } catch (SQLException e) {
            logger.error("Database error retrieving transactions for user {}: {}", userId, e.getMessage());
        } finally {
            try {
                if (rs != null) rs.close();
                if (pstmt != null) pstmt.close();
                if (conn != null) conn.close();
            } catch (SQLException e) {
                logger.error("Error closing resources after retrieving transactions: {}", e.getMessage());
            }
        }
        return transactions;
    }

    /**
     * Calculates the current balance for a user.
     *
     * @param userId The ID of the user.
     * @return The current balance (sum of income - sum of expenses).
     */
    public BigDecimal getBalanceByUserId(int userId) {
        BigDecimal balance = BigDecimal.ZERO;
        String sql = "SELECT type, amount FROM transactions WHERE user_id = ?";
        Connection conn = null;
        PreparedStatement pstmt = null;
        ResultSet rs = null;

        try {
            conn = DatabaseUtil.getConnection();
            pstmt = conn.prepareStatement(sql);
            pstmt.setInt(1, userId);
            rs = pstmt.executeQuery();

            while (rs.next()) {
                Transaction.Type type = Transaction.Type.valueOf(rs.getString("type"));
                BigDecimal amount = rs.getBigDecimal("amount");

                if (type == Transaction.Type.INCOME) {
                    balance = balance.add(amount);
                } else {
                    balance = balance.subtract(amount);
                }
            }
            logger.debug("Calculated balance for user {}: {}", userId, balance);
        } catch (SQLException e) {
            logger.error("Database error calculating balance for user {}: {}", userId, e.getMessage());
        } finally {
            try {
                if (rs != null) rs.close();
                if (pstmt != null) pstmt.close();
                if (conn != null) conn.close();
            } catch (SQLException e) {
                logger.error("Error closing resources after calculating balance: {}", e.getMessage());
            }
        }
        return balance;
    }
}

