    private static final Scanner scanner = new Scanner(System.in);
    private static final AuthService authService = new AuthService();
    private static final TransactionService transactionService = new TransactionService();
    private static User currentUser = null;

    public static void main(String[] args) {
        // --- SECURE CODING REQUIREMENTS NOTES ---
        // 1. PreparedStatement for all SQL: Implemented in AuthService and TransactionService.
        // 2. Hash passwords with BCrypt: Implemented in PasswordUtil and used by AuthService.
        // 3. No secrets in code; use environment variables/config: DatabaseUtil reads DB_URL, DB_USER, DB_PASSWORD from environment variables.
        // 4. Add security headers (X-Content-Type-Options, Referrer-Policy, etc.):
        //    This is a command-line application, so HTTP security headers are not applicable.
        //    In a web application (e.g., Spring Boot), these would be configured via a SecurityConfig class
        //    or web server settings (e.g., Nginx, Apache).
        // 5. Block SSRF to internal IPs:
        //    This is also not applicable to a simple command-line application that doesn't make outbound HTTP requests.
        //    In a web application that makes external requests, this would involve validating URLs before making requests
        //    to ensure they don't resolve to private IP ranges (127.0.0.1, 10/8, 172.16/12, 192.168/16, 169.254/16).
        // 6. Log without sensitive data; redact tokens/passwords/emails:
        //    Implemented using SLF4J/Logback. Sensitive data like plain passwords are not logged.
        //    PasswordUtil logs "Password check failed for a user (sensitive data redacted)" instead of username.
        // --- END SECURE CODING REQUIREMENTS NOTES ---

        logger.info("Starting Finance Management System...");

        // Basic database connection test
        try (Connection conn = DatabaseUtil.getConnection()) {
            if (conn != null) {
                logger.info("Successfully connected to the database.");
            }
        } catch (SQLException e) {
            logger.error("Failed to connect to the database. Please ensure DB_URL, DB_USER, DB_PASSWORD environment variables are set and the database is running. Error: {}", e.getMessage());
