     *
     * @param username The desired username.
     * @param password The plain-text password.
     * @return The registered User object if successful, null otherwise.
     */
    public User registerUser(String username, String password) {
        if (username == null || username.trim().isEmpty() || password == null || password.isEmpty()) {
            logger.warn("Attempted to register user with invalid username or password.");
            return null;
        }

        String hashedPassword = PasswordUtil.hashPassword(password);
        String sql = "INSERT INTO users (username, password_hash) VALUES (?, ?)";
        Connection conn = null;
        PreparedStatement pstmt = null;
        ResultSet rs = null;
        User newUser = null;

        try {
            conn = DatabaseUtil.getConnection();
            pstmt = conn.prepareStatement(sql, Statement.RETURN_GENERATED_KEYS);
            pstmt.setString(1, username);
            pstmt.setString(2, hashedPassword);

            int affectedRows = pstmt.executeUpdate();
            if (affectedRows > 0) {
                rs = pstmt.getGeneratedKeys();
                if (rs.next()) {
                    int id = rs.getInt(1);
                    newUser = new User(id, username, hashedPassword);
                    logger.info("User registered successfully: {}", username);
                }
            } else {
                logger.warn("User registration failed for username: {}", username);
            }
        } catch (SQLException e) {
            if (e.getSQLState().equals("23000")) { // SQLState for duplicate entry (e.g., unique constraint violation)
                logger.warn("Registration failed: Username '{}' already exists.", username);
            } else {
                logger.error("Database error during user registration for {}: {}", username, e.getMessage());
            }
        } finally {
            try {
                if (rs != null) rs.close();
                if (pstmt != null) pstmt.close();
                if (conn != null) conn.close();
            } catch (SQLException e) {
                logger.error("Error closing resources after registration: {}", e.getMessage());
            }
        }
