package com.pms.util;

import org.mindrot.jbcrypt.BCrypt;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

public class PasswordUtil {

    private static final Logger logger = LoggerFactory.getLogger(PasswordUtil.class);

    /**
     * Hashes a plain-text password using BCrypt.
     *
     * @param plainPassword The plain-text password.
     * @return The BCrypt hashed password.
     */
    public static String hashPassword(String plainPassword) {
        if (plainPassword == null || plainPassword.isEmpty()) {
            logger.warn("Attempted to hash a null or empty password.");
            throw new IllegalArgumentException("Password cannot be null or empty.");
        }
        // Generate a salt and hash the password
        String hashedPassword = BCrypt.hashpw(plainPassword, BCrypt.gensalt());
        logger.debug("Password hashed successfully.");
        return hashedPassword;
    }

    /**
     * Checks if a plain-text password matches a BCrypt hashed password.
     *
     * @param plainPassword The plain-text password to check.
     * @param hashedPassword The BCrypt hashed password from the database.
     * @return true if the passwords match, false otherwise.
     */
    public static boolean checkPassword(String plainPassword, String hashedPassword) {
        if (plainPassword == null || hashedPassword == null) {
            logger.warn("Attempted to check password with null plain or hashed password.");
            return false;
        }
        try {
            boolean matches = BCrypt.checkpw(plainPassword, hashedPassword);
            if (!matches) {
                logger.debug("Password check failed for provided plain password.");
            }
            return matches;
        } catch (IllegalArgumentException e) {
            logger.error("Error during password check, possibly invalid hash format: {}", e.getMessage());
            return false;
        }
    }
}
