package com.pms.util;

import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

import java.io.IOException;
import java.io.InputStream;
import java.sql.Connection;
import java.sql.DriverManager;
import java.sql.SQLException;
import java.util.Properties;

public class DatabaseUtil {

    private static final Logger logger = LoggerFactory.getLogger(DatabaseUtil.class);
    private static final Properties properties = new Properties();

    static {
        try (InputStream input = DatabaseUtil.class.getClassLoader().getResourceAsStream("application.properties")) {
            if (input == null) {
                logger.error("Sorry, unable to find application.properties");
                throw new IOException("application.properties not found.");
            }
            properties.load(input);
            logger.info("Database properties loaded successfully.");
        } catch (IOException ex) {
            logger.error("Error loading database properties: {}", ex.getMessage(), ex);
            throw new RuntimeException("Failed to load database properties.", ex);
        }
    }

    /**
     * Establishes a connection to the database.
     *
     * @return A valid database connection.
     * @throws SQLException if a database access error occurs.
     */
    public static Connection getConnection() throws SQLException {
        String url = properties.getProperty("db.url");
        String username = properties.getProperty("db.username");
        String password = properties.getProperty("db.password"); // In production, load from env or vault

        if (url == null || username == null || password == null) {
            logger.error("Database connection properties are not fully configured.");
            throw new SQLException("Database connection properties (url, username, password) must be set.");
        }

        try {
            Connection connection = DriverManager.getConnection(url, username, password);
            logger.debug("Database connection established successfully.");
            return connection;
        } catch (SQLException e) {
            logger.error("Failed to establish database connection: {}", e.getMessage(), e);
            throw e;
        }
    }

    /**
     * Closes a database connection, statement, and result set safely.
     *
     * @param connection The connection to close.
     * @param statement The statement to close.
     * @param resultSet The result set to close.
     */
    public static void close(AutoCloseable... closeables) {
        for (AutoCloseable closeable : closeables) {
            if (closeable != null) {
                try {
                    closeable.close();
                } catch (Exception e) {
                    logger.error("Error closing resource: {}", e.getMessage(), e);
                }
            }
        }
    }
}
