package com.pms.service;

import com.pms.dao.UserDAO;
import com.pms.model.User;
import com.pms.util.PasswordUtil;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

import java.util.List;
import java.util.Optional;

public class UserService {

    private static final Logger logger = LoggerFactory.getLogger(UserService.class);
    private final UserDAO userDAO;

    public UserService(UserDAO userDAO) {
        this.userDAO = userDAO;
    }

    /**
     * Registers a new user with a hashed password.
     *
     * @param username The user's chosen username.
     * @param plainPassword The user's plain-text password.
     * @param role The user's role (e.g., ADMIN, MANAGER, TENANT).
     * @return An Optional containing the created User object if successful, empty otherwise.
     */
    public Optional<User> registerUser(String username, String plainPassword, String role) {
        if (userDAO.getUserByUsername(username).isPresent()) {
            logger.warn("Registration failed: Username '{}' already exists.", username);
            return Optional.empty();
        }

        String hashedPassword = PasswordUtil.hashPassword(plainPassword);
        User newUser = new User(username, hashedPassword, role);
        Optional<User> createdUser = userDAO.createUser(newUser);
        if (createdUser.isPresent()) {
            logger.info("User '{}' registered successfully with role '{}'.", username, role);
        } else {
            logger.error("Failed to register user '{}'.", username);
        }
        return createdUser;
    }

    /**
     * Authenticates a user by checking their username and password.
     *
     * @param username The user's username.
     * @param plainPassword The plain-text password provided by the user.
     * @return An Optional containing the authenticated User object if successful, empty otherwise.
     */
    public Optional<User> authenticateUser(String username, String plainPassword) {
        Optional<User> userOptional = userDAO.getUserByUsername(username);
        if (userOptional.isPresent()) {
            User user = userOptional.get();
            if (PasswordUtil.checkPassword(plainPassword, user.getPasswordHash())) {
                logger.info("User '{}' authenticated successfully.", username);
                return Optional.of(user);
            } else {
                logger.warn("Authentication failed for user '{}': Incorrect password.", username);
            }
        } else {
            logger.warn("Authentication failed: User '{}' not found.", username);
        }
        return Optional.empty();
    }

    /**
     * Updates a user's password.
     *
     * @param userId The ID of the user to update.
     * @param newPlainPassword The new plain-text password.
     * @return true if the password was updated successfully, false otherwise.
     */
    public boolean updateUserPassword(int userId, String newPlainPassword) {
        Optional<User> userOptional = userDAO.getUserById(userId);
        if (userOptional.isPresent()) {
            User user = userOptional.get();
            String newHashedPassword = PasswordUtil.hashPassword(newPlainPassword);
            user.setPasswordHash(newHashedPassword);
            boolean updated = userDAO.updateUser(user);
            if (updated) {
                logger.info("Password updated successfully for user ID: {}", userId);
            } else {
                logger.error("Failed to update password for user ID: {}", userId);
            }
            return updated;
        } else {
            logger.warn("Password update failed: User with ID {} not found.", userId);
            return false;
        }
    }

    public Optional<User> getUserById(int id) {
        return userDAO.getUserById(id);
    }

    public Optional<User> getUserByUsername(String username) {
        return userDAO.getUserByUsername(username);
    }

    public List<User> getAllUsers() {
        return userDAO.getAllUsers();
    }

    public boolean updateUser(User user) {
        // Note: This method should be used carefully, especially for password updates.
        // For password updates, use updateUserPassword.
        // If updating other fields, ensure password_hash is not accidentally overwritten with plain text.
        // The DAO expects a hashed password.
        return userDAO.updateUser(user);
    }

    public boolean deleteUser(int id) {
        boolean deleted = userDAO.deleteUser(id);
        if (deleted) {
            logger.info("User with ID {} deleted successfully.", id);
        } else {
            logger.warn("Failed to delete user with ID {}.", id);
        }
        return deleted;
    }
}
