public class PropertyService {

    private static final Logger logger = LoggerFactory.getLogger(PropertyService.class);
    private final PropertyDAO propertyDAO;

    public PropertyService(PropertyDAO propertyDAO) {
        this.propertyDAO = propertyDAO;
    }

    public Optional<Property> addProperty(String address, String type, BigDecimal rentAmount, Integer ownerId) {
        if (rentAmount.compareTo(BigDecimal.ZERO) <= 0) {
            logger.warn("Attempted to add property with non-positive rent amount: {}", rentAmount);
            return Optional.empty();
        }
        Property newProperty = new Property(address, type, rentAmount, ownerId);
        Optional<Property> createdProperty = propertyDAO.createProperty(newProperty);
        if (createdProperty.isPresent()) {
            logger.info("Property added successfully: {}", createdProperty.get().getAddress());
        } else {
            logger.error("Failed to add property: {}", address);
        }
        return createdProperty;
    }

    public Optional<Property> getPropertyById(int id) {
        return propertyDAO.getPropertyById(id);
    }

    public List<Property> getAllProperties() {
        return propertyDAO.getAllProperties();
    }

    public boolean updateProperty(Property property) {
        if (property.getRentAmount().compareTo(BigDecimal.ZERO) <= 0) {
            logger.warn("Attempted to update property {} with non-positive rent amount: {}", property.getId(), property.getRentAmount());
            return false;
        }
        boolean updated = propertyDAO.updateProperty(property);
        if (updated) {
            logger.info("Property ID {} updated successfully.", property.getId());
        } else {
            logger.warn("Failed to update property ID {}.", property.getId());
        }
        return updated;
    }

    public boolean deleteProperty(int id) {
        boolean deleted = propertyDAO.deleteProperty(id);
        if (deleted) {
            logger.info("Property ID {} deleted successfully.", id);
        } else {
            logger.warn("Failed to delete property ID {}.", id);
        }
        return deleted;
    }
