            logger.warn("Attempted to add tenant with invalid lease dates: start {} after end {}", leaseStartDate, leaseEndDate);
            return Optional.empty();
        }
        Tenant newTenant = new Tenant(name, contactInfo, propertyId, leaseStartDate, leaseEndDate);
        Optional<Tenant> createdTenant = tenantDAO.createTenant(newTenant);
        if (createdTenant.isPresent()) {
            logger.info("Tenant added successfully: {}", createdTenant.get().getName());
        } else {
            logger.error("Failed to add tenant: {}", name);
        }
        return createdTenant;
    }

    public Optional<Tenant> getTenantById(int id) {
        return tenantDAO.getTenantById(id);
    }

    public List<Tenant> getAllTenants() {
        return tenantDAO.getAllTenants();
    }

    public boolean updateTenant(Tenant tenant) {
        if (tenant.getLeaseStartDate() != null && tenant.getLeaseEndDate() != null && tenant.getLeaseStartDate().isAfter(tenant.getLeaseEndDate())) {
            logger.warn("Attempted to update tenant {} with invalid lease dates: start {} after end {}", tenant.getId(), tenant.getLeaseStartDate(), tenant.getLeaseEndDate());
            return false;
        }
        boolean updated = tenantDAO.updateTenant(tenant);
        if (updated) {
            logger.info("Tenant ID {} updated successfully.", tenant.getId());
        } else {
            logger.warn("Failed to update tenant ID {}.", tenant.getId());
        }
        return updated;
    }

    public boolean deleteTenant(int id) {
        boolean deleted = tenantDAO.deleteTenant(id);
        if (deleted) {
            logger.info("Tenant ID {} deleted successfully.", id);
        } else {
            logger.warn("Failed to delete tenant ID {}.", id);
        }
        return deleted;
    }
