    id INT AUTO_INCREMENT PRIMARY KEY,
    name VARCHAR(100) NOT NULL,
    contact_info VARCHAR(255), -- e.g., email, phone
    property_id INT, -- Foreign key to Properties table
    lease_start_date DATE,
    lease_end_date DATE,
    FOREIGN KEY (property_id) REFERENCES Properties(id) ON DELETE SET NULL
);

-- Create LeaseAgreements table (more detailed lease management)
CREATE TABLE IF NOT EXISTS LeaseAgreements (
    id INT AUTO_INCREMENT PRIMARY KEY,
    tenant_id INT NOT NULL,
    property_id INT NOT NULL,
    start_date DATE NOT NULL,
    end_date DATE NOT NULL,
    monthly_rent DECIMAL(10, 2) NOT NULL,
    status VARCHAR(20) NOT NULL, -- e.g., 'ACTIVE', 'EXPIRED', 'PENDING'
    FOREIGN KEY (tenant_id) REFERENCES Tenants(id) ON DELETE CASCADE,
    FOREIGN KEY (property_id) REFERENCES Properties(id) ON DELETE CASCADE
);

-- Create MaintenanceRequests table
CREATE TABLE IF NOT EXISTS MaintenanceRequests (
    id INT AUTO_INCREMENT PRIMARY KEY,
    property_id INT NOT NULL,
    tenant_id INT, -- Optional, if request comes from a specific tenant
    description VARCHAR(500) NOT NULL,
    request_date TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    status VARCHAR(20) NOT NULL, -- e.g., 'OPEN', 'IN_PROGRESS', 'COMPLETED', 'CLOSED'
    priority VARCHAR(20), -- e.g., 'LOW', 'MEDIUM', 'HIGH', 'URGENT'
    completion_date TIMESTAMP,
    FOREIGN KEY (property_id) REFERENCES Properties(id) ON DELETE CASCADE,
    FOREIGN KEY (tenant_id) REFERENCES Tenants(id) ON DELETE SET NULL
);
