package com.library;

import com.library.db.DatabaseManager;
import com.library.model.Book;
import com.library.model.User;
import com.library.service.AuthService;
import com.library.service.LibraryService;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

import java.sql.SQLException;
import java.util.List;
import java.util.Scanner;

public class Main {
    private static final Logger logger = LoggerFactory.getLogger(Main.class);
    private static Scanner scanner = new Scanner(System.in);
    private static AuthService authService;
    private static LibraryService libraryService;
    private static User currentUser;

    public static void main(String[] args) {
        // Initialize DatabaseManager and services
        try {
            DatabaseManager.init();
            authService = new AuthService();
            libraryService = new LibraryService();
            logger.info("Library Management System initialized successfully.");
        } catch (SQLException e) {
            logger.error("Failed to initialize database or services: {}", e.getMessage());
            System.err.println("Error initializing system. Please check logs.");
            return;
        }

        while (true) {
            if (currentUser == null) {
                showAuthMenu();
            } else {
                showMainMenu();
            }
        }
    }

    private static void showAuthMenu() {
        System.out.println("\n--- Authentication Menu ---");
        System.out.println("1. Register");
        System.out.println("2. Login");
        System.out.println("3. Exit");
        System.out.print("Enter choice: ");
        String choice = scanner.nextLine();

        switch (choice) {
            case "1":
                registerUser();
                break;
            case "2":
                loginUser();
                break;
            case "3":
                System.out.println("Exiting application. Goodbye!");
                System.exit(0);
                break;
            default:
                System.out.println("Invalid choice. Please try again.");
        }
    }

    private static void registerUser() {
        System.out.print("Enter username: ");
        String username = scanner.nextLine();
        System.out.print("Enter password: ");
        String password = scanner.nextLine();
        System.out.print("Enter role (ADMIN/MEMBER): ");
        String role = scanner.nextLine().toUpperCase();

        try {
            if (authService.register(username, password, role)) {
                System.out.println("Registration successful for user: " + username);
                logger.info("User registered: {}", username);
            } else {
                System.out.println("Registration failed. Username might already exist or invalid role.");
            }
        } catch (SQLException e) {
            logger.error("Error during registration for user {}: {}", username, e.getMessage());
            System.out.println("An error occurred during registration. Please try again.");
        }
    }

    private static void loginUser() {
        System.out.print("Enter username: ");
        String username = scanner.nextLine();
        System.out.print("Enter password: ");
        String password = scanner.nextLine();

        try {
            currentUser = authService.login(username, password);
            if (currentUser != null) {
                System.out.println("Login successful! Welcome, " + currentUser.getUsername() + " (" + currentUser.getRole() + ")");
                logger.info("User logged in: {}", currentUser.getUsername());
            } else {
                System.out.println("Login failed. Invalid username or password.");
                logger.warn("Failed login attempt for user: {}", username);
            }
        } catch (SQLException e) {
            logger.error("Error during login for user {}: {}", username, e.getMessage());
            System.out.println("An error occurred during login. Please try again.");
        }
    }

    private static void showMainMenu() {
        System.out.println("\n--- Main Menu ---");
        System.out.println("Logged in as: " + currentUser.getUsername() + " (" + currentUser.getRole() + ")");
        System.out.println("1. List All Books");
        System.out.println("2. Borrow Book");
        System.out.println("3. Return Book");
        if ("ADMIN".equals(currentUser.getRole())) {
            System.out.println("4. Add Book");
            System.out.println("5. Remove Book");
        }
        System.out.println("0. Logout");
        System.out.print("Enter choice: ");
        String choice = scanner.nextLine();

        switch (choice) {
            case "1":
                listAllBooks();
                break;
            case "2":
                borrowBook();
                break;
            case "3":
                returnBook();
                break;
            case "4":
                if ("ADMIN".equals(currentUser.getRole())) addBook();
                else System.out.println("Access denied. Admin privileges required.");
                break;
            case "5":
                if ("ADMIN".equals(currentUser.getRole())) removeBook();
                else System.out.println("Access denied. Admin privileges required.");
                break;
            case "0":
                currentUser = null;
                System.out.println("Logged out successfully.");
                logger.info("User logged out.");
                break;
            default:
                System.out.println("Invalid choice. Please try again.");
        }
    }

    private static void listAllBooks() {
        try {
            List<Book> books = libraryService.getAllBooks();
            if (books.isEmpty()) {
                System.out.println("No books available in the library.");
                return;
            }
            System.out.println("\n--- All Books ---");
            System.out.printf("%-5s %-30s %-20s %-10s%n", "ID", "Title", "Author", "Available");
            System.out.println("-------------------------------------------------------------------");
            for (Book book : books) {
                System.out.printf("%-5d %-30s %-20s %-10b%n",
                        book.getId(), book.getTitle(), book.getAuthor(), book.isAvailable());
            }
        } catch (SQLException e) {
            logger.error("Error listing all books: {}", e.getMessage());
            System.out.println("An error occurred while fetching books.");
        }
    }

    private static void borrowBook() {
        System.out.print("Enter Book ID to borrow: ");
        try {
            int bookId = Integer.parseInt(scanner.nextLine());
            if (libraryService.borrowBook(currentUser.getId(), bookId)) {
                System.out.println("Book borrowed successfully!");
                logger.info("User {} borrowed book ID {}", currentUser.getUsername(), bookId);
            } else {
                System.out.println("Failed to borrow book. It might be unavailable or invalid ID.");
            }
        } catch (NumberFormatException e) {
            System.out.println("Invalid Book ID. Please enter a number.");
        } catch (SQLException e) {
            logger.error("Error borrowing book for user {}: {}", currentUser.getUsername(), e.getMessage());
            System.out.println("An error occurred while borrowing the book.");
        }
    }

    private static void returnBook() {
        System.out.print("Enter Book ID to return: ");
        try {
            int bookId = Integer.parseInt(scanner.nextLine());
            if (libraryService.returnBook(currentUser.getId(), bookId)) {
                System.out.println("Book returned successfully!");
                logger.info("User {} returned book ID {}", currentUser.getUsername(), bookId);
            } else {
                System.out.println("Failed to return book. It might not have been borrowed by you or invalid ID.");
            }
        } catch (NumberFormatException e) {
            System.out.println("Invalid Book ID. Please enter a number.");
        } catch (SQLException e) {
            logger.error("Error returning book for user {}: {}", currentUser.getUsername(), e.getMessage());
            System.out.println("An error occurred while returning the book.");
        }
    }

    private static void addBook() {
        System.out.print("Enter book title: ");
        String title = scanner.nextLine();
        System.out.print("Enter book author: ");
        String author = scanner.nextLine();

        try {
            if (libraryService.addBook(title, author)) {
                System.out.println("Book added successfully!");
                logger.info("Admin {} added book: {} by {}", currentUser.getUsername(), title, author);
            } else {
                System.out.println("Failed to add book.");
            }
        } catch (SQLException e) {
            logger.error("Error adding book by admin {}: {}", currentUser.getUsername(), e.getMessage());
            System.out.println("An error occurred while adding the book.");
        }
    }

    private static void removeBook() {
        System.out.print("Enter Book ID to remove: ");
        try {
            int bookId = Integer.parseInt(scanner.nextLine());
            if (libraryService.removeBook(bookId)) {
                System.out.println("Book removed successfully!");
                logger.info("Admin {} removed book ID {}", currentUser.getUsername(), bookId);
            } else {
                System.out.println("Failed to remove book. Book might be borrowed or invalid ID.");
            }
        } catch (NumberFormatException e) {
            System.out.println("Invalid Book ID. Please enter a number.");
        } catch (SQLException e) {
            logger.error("Error removing book by admin {}: {}", currentUser.getUsername(), e.getMessage());
            System.out.println("An error occurred while removing the book.");
        }
    }
}
