    }

    public static void init() throws SQLException {
        try (Connection conn = getConnection()) {
            createTables(conn);
            logger.info("Database initialized successfully. Using URL: {}", DB_URL);
        } catch (SQLException e) {
            logger.error("Failed to initialize database: {}", e.getMessage());
            throw e;
        }
    }

    public static Connection getConnection() throws SQLException {
        return DriverManager.getConnection(DB_URL, DB_USER, DB_PASSWORD);
    }

    private static void createTables(Connection conn) throws SQLException {
        try (Statement stmt = conn.createStatement()) {
            // Create Users table
            stmt.execute("CREATE TABLE IF NOT EXISTS users (" +
                         "id INT AUTO_INCREMENT PRIMARY KEY," +
                         "username VARCHAR(50) NOT NULL UNIQUE," +
                         "password_hash VARCHAR(60) NOT NULL," + // BCrypt hashes are 60 chars
                         "role VARCHAR(10) NOT NULL CHECK (role IN ('ADMIN', 'MEMBER'))" +
                         ")");
            logger.debug("Table 'users' checked/created.");

            // Create Books table
            stmt.execute("CREATE TABLE IF NOT EXISTS books (" +
                         "id INT AUTO_INCREMENT PRIMARY KEY," +
                         "title VARCHAR(255) NOT NULL," +
                         "author VARCHAR(255) NOT NULL," +
                         "is_available BOOLEAN DEFAULT TRUE" +
                         ")");
            logger.debug("Table 'books' checked/created.");

            // Create Borrowings table
            stmt.execute("CREATE TABLE IF NOT EXISTS borrowings (" +
                         "id INT AUTO_INCREMENT PRIMARY KEY," +
                         "user_id INT NOT NULL," +
                         "book_id INT NOT NULL," +
                         "borrow_date TIMESTAMP DEFAULT CURRENT_TIMESTAMP," +
                         "return_date TIMESTAMP," +
                         "FOREIGN KEY (user_id) REFERENCES users(id)," +
                         "FOREIGN KEY (book_id) REFERENCES books(id)," +
                         "UNIQUE (user_id, book_id, return_date)" + // A user can borrow a book multiple times, but only one active borrowing at a time
                         ")");
            logger.debug("Table 'borrowings' checked/created.");

        } catch (SQLException e) {
            logger.error("Error creating tables: {}", e.getMessage());
            throw e;
        }
    }
}
