        try (Connection conn = DatabaseManager.getConnection();
             PreparedStatement pstmt = conn.prepareStatement(sql)) {
            pstmt.setInt(1, id);
            try (ResultSet rs = pstmt.executeQuery()) {
                if (rs.next()) {
                    return new Book(
                            rs.getInt("id"),
                            rs.getString("title"),
                            rs.getString("author"),
                            rs.getBoolean("is_available")
                    );
                }
            }
        } catch (SQLException e) {
            logger.error("Error finding book by ID {}: {}", id, e.getMessage());
            throw e;
        }
        return null;
    }

    public List<Book> getAllBooks() throws SQLException {
        List<Book> books = new ArrayList<>();
        String sql = "SELECT id, title, author, is_available FROM books ORDER BY title";
        try (Connection conn = DatabaseManager.getConnection();
             PreparedStatement pstmt = conn.prepareStatement(sql);
             ResultSet rs = pstmt.executeQuery()) {
            while (rs.next()) {
                books.add(new Book(
                        rs.getInt("id"),
                        rs.getString("title"),
                        rs.getString("author"),
                        rs.getBoolean("is_available")
                ));
            }
        } catch (SQLException e) {
            logger.error("Error getting all books: {}", e.getMessage());
            throw e;
        }
        return books;
    }

    public boolean createBook(Book book) throws SQLException {
        String sql = "INSERT INTO books (title, author, is_available) VALUES (?, ?, ?)";
        try (Connection conn = DatabaseManager.getConnection();
             PreparedStatement pstmt = conn.prepareStatement(sql, Statement.RETURN_GENERATED_KEYS)) {
            pstmt.setString(1, book.getTitle());
            pstmt.setString(2, book.getAuthor());
            pstmt.setBoolean(3, book.isAvailable());

            int affectedRows = pstmt.executeUpdate();
            if (affectedRows > 0) {
                try (ResultSet generatedKeys = pstmt.getGeneratedKeys()) {
                    if (generatedKeys.next()) {
                        book.setId(generatedKeys.getInt(1));
                    }
                }
                logger.info("Book created: {} by {}", book.getTitle(), book.getAuthor());
                return true;
            }
        } catch (SQLException e) {
            logger.error("Error creating book {}: {}", book.getTitle(), e.getMessage());
            throw e;
        }
        return false;
    }

