public class BorrowingDAO {
    private static final Logger logger = LoggerFactory.getLogger(BorrowingDAO.class);

    public boolean createBorrowing(Borrowing borrowing) throws SQLException {
        String sql = "INSERT INTO borrowings (user_id, book_id, borrow_date) VALUES (?, ?, ?)";
        try (Connection conn = DatabaseManager.getConnection();
             PreparedStatement pstmt = conn.prepareStatement(sql, Statement.RETURN_GENERATED_KEYS)) {
            pstmt.setInt(1, borrowing.getUserId());
            pstmt.setInt(2, borrowing.getBookId());
            pstmt.setTimestamp(3, Timestamp.valueOf(borrowing.getBorrowDate()));

            int affectedRows = pstmt.executeUpdate();
            if (affectedRows > 0) {
                try (ResultSet generatedKeys = pstmt.getGeneratedKeys()) {
                    if (generatedKeys.next()) {
                        borrowing.setId(generatedKeys.getInt(1));
                    }
                }
                logger.info("Borrowing created: User ID {}, Book ID {}", borrowing.getUserId(), borrowing.getBookId());
                return true;
            }
        } catch (SQLException e) {
            logger.error("Error creating borrowing for user {} book {}: {}",
                    borrowing.getUserId(), borrowing.getBookId(), e.getMessage());
            throw e;
        }
        return false;
    }

    public Borrowing findActiveBorrowing(int userId, int bookId) throws SQLException {
        String sql = "SELECT id, user_id, book_id, borrow_date, return_date FROM borrowings " +
                     "WHERE user_id = ? AND book_id = ? AND return_date IS NULL";
        try (Connection conn = DatabaseManager.getConnection();
             PreparedStatement pstmt = conn.prepareStatement(sql)) {
            pstmt.setInt(1, userId);
            pstmt.setInt(2, bookId);
            try (ResultSet rs = pstmt.executeQuery()) {
                if (rs.next()) {
                    return new Borrowing(
                            rs.getInt("id"),
                            rs.getInt("user_id"),
                            rs.getInt("book_id"),
                            rs.getTimestamp("borrow_date").toLocalDateTime(),
                            null // return_date is null for active borrowing
                    );
                }
            }
        } catch (SQLException e) {
            logger.error("Error finding active borrowing for user {} book {}: {}", userId, bookId, e.getMessage());
            throw e;
        }
        return null;
    }

    public boolean updateReturnDate(int borrowingId, LocalDateTime returnDate) throws SQLException {
        String sql = "UPDATE borrowings SET return_date = ? WHERE id = ?";
        try (Connection conn = DatabaseManager.getConnection();
             PreparedStatement pstmt = conn.prepareStatement(sql)) {
            pstmt.setTimestamp(1, Timestamp.valueOf(returnDate));
            pstmt.setInt(2, borrowingId);

            int affectedRows = pstmt.executeUpdate();
            if (affectedRows > 0) {
                logger.info("Borrowing ID {} return date updated.", borrowingId);
                return true;
            }
        } catch (SQLException e) {
            logger.error("Error updating return date for borrowing ID {}: {}", borrowingId, e.getMessage());
            throw e;
        }
        return false;
    }

    public List<Borrowing> getBorrowingsByUserId(int userId) throws SQLException {
        List<Borrowing> borrowings = new ArrayList<>();
        String sql = "SELECT id, user_id, book_id, borrow_date, return_date FROM borrowings WHERE user_id = ? ORDER BY borrow_date DESC";
        try (Connection conn = DatabaseManager.getConnection();
             PreparedStatement pstmt = conn.prepareStatement(sql)) {
            pstmt.setInt(1, userId);
            try (ResultSet rs = pstmt.executeQuery()) {
                while (rs.next()) {
                    borrowings.add(new Borrowing(
                            rs.getInt("id"),
                            rs.getInt("user_id"),
                            rs.getInt("book_id"),
                            rs.getTimestamp("borrow_date").toLocalDateTime(),
                            rs.getTimestamp("return_date") != null ? rs.getTimestamp("return_date").toLocalDateTime() : null
                    ));
                }
            }
        } catch (SQLException e) {
            logger.error("Error getting borrowings for user ID {}: {}", userId, e.getMessage());
            throw e;
        }
        return borrowings;
    }
