package com.library.service;

import com.library.dao.UserDAO;
import com.library.model.User;
import com.library.util.PasswordUtil;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

import java.sql.SQLException;

public class AuthService {
    private static final Logger logger = LoggerFactory.getLogger(AuthService.class);
    private UserDAO userDAO;

    public AuthService() {
        this.userDAO = new UserDAO();
    }

    public boolean register(String username, String password, String role) throws SQLException {
        if (username == null || username.trim().isEmpty() || password == null || password.isEmpty()) {
            logger.warn("Attempted registration with empty username or password.");
            return false;
        }
        if (!"ADMIN".equals(role) && !"MEMBER".equals(role)) {
            logger.warn("Attempted registration with invalid role: {}", role);
            return false;
        }

        // Check if username already exists
        if (userDAO.findByUsername(username) != null) {
            logger.warn("Registration failed: Username '{}' already exists.", username);
            return false;
        }

        String hashedPassword = PasswordUtil.hashPassword(password);
        User newUser = new User(username, hashedPassword, role);
        return userDAO.createUser(newUser);
    }

    public User login(String username, String password) throws SQLException {
        if (username == null || username.trim().isEmpty() || password == null || password.isEmpty()) {
            logger.warn("Attempted login with empty username or password.");
            return null;
        }

        User user = userDAO.findByUsername(username);
        if (user != null && PasswordUtil.checkPassword(password, user.getPasswordHash())) {
            logger.info("User '{}' logged in successfully.", username);
            return user;
        }
        logger.warn("Login failed for user '{}'. Invalid credentials.", username);
        return null;
    }
}
