package com.library.service;

import com.library.dao.BookDAO;
import com.library.dao.BorrowingDAO;
import com.library.model.Book;
import com.library.model.Borrowing;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

import java.sql.SQLException;
import java.time.LocalDateTime;
import java.util.List;

public class LibraryService {
    private static final Logger logger = LoggerFactory.getLogger(LibraryService.class);
    private BookDAO bookDAO;
    private BorrowingDAO borrowingDAO;

    public LibraryService() {
        this.bookDAO = new BookDAO();
        this.borrowingDAO = new BorrowingDAO();
    }

    public boolean addBook(String title, String author) throws SQLException {
        if (title == null || title.trim().isEmpty() || author == null || author.trim().isEmpty()) {
            logger.warn("Attempted to add book with empty title or author.");
            return false;
        }
        Book newBook = new Book(title, author, true); // New books are available by default
        return bookDAO.createBook(newBook);
    }

    public boolean removeBook(int bookId) throws SQLException {
        Book book = bookDAO.findBookById(bookId);
        if (book == null) {
            logger.warn("Attempted to remove non-existent book ID: {}", bookId);
            return false;
        }
        if (!book.isAvailable()) {
            logger.warn("Attempted to remove book ID {} which is currently borrowed.", bookId);
            // In a real system, you might prevent deletion if borrowed, or force return first.
            // For simplicity, we'll prevent it here.
            return false;
        }
        return bookDAO.deleteBook(bookId);
    }

    public List<Book> getAllBooks() throws SQLException {
        return bookDAO.getAllBooks();
    }

    public boolean borrowBook(int userId, int bookId) throws SQLException {
        Book book = bookDAO.findBookById(bookId);
        if (book == null || !book.isAvailable()) {
            logger.warn("Failed to borrow book ID {}: Book not found or not available.", bookId);
            return false;
        }

        // Check if the user already has an active borrowing for this book
        if (borrowingDAO.findActiveBorrowing(userId, bookId) != null) {
            logger.warn("User {} already has an active borrowing for book ID {}.", userId, bookId);
            return false;
        }

        // Create borrowing record
        Borrowing newBorrowing = new Borrowing(userId, bookId, LocalDateTime.now());
        if (borrowingDAO.createBorrowing(newBorrowing)) {
            // Update book availability
            return bookDAO.updateBookAvailability(bookId, false);
        }
        return false;
    }

    public boolean returnBook(int userId, int bookId) throws SQLException {
        // Find active borrowing for this user and book
        Borrowing activeBorrowing = borrowingDAO.findActiveBorrowing(userId, bookId);
        if (activeBorrowing == null) {
            logger.warn("Failed to return book ID {} by user {}: No active borrowing found.", bookId, userId);
            return false;
        }

        // Update borrowing record with return date
        if (borrowingDAO.updateReturnDate(activeBorrowing.getId(), LocalDateTime.now())) {
            // Update book availability
            return bookDAO.updateBookAvailability(bookId, true);
        }
        return false;
    }
}
